{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_OyV0OOpE0NjYbCvJHejt60","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\tATR波动率扩张突破识别\n4\t筛选创业板中波动率扩张的股票\n5\t\"\"\"\n6\tfrom mootdx.quotes import Quotes\n7\timport pandas as pd\n8\timport numpy as np\n9\tfrom datetime import datetime, timedelta\n10\t\n11\tdef calculate_atr(df, period=14):\n12\t    \"\"\"\n13\t    计算ATR（Average True Range）使用Wilder平滑法\n14\t    \"\"\"\n15\t    # 计算True Range\n16\t    high = df['high'].values\n17\t    low = df['low'].values\n18\t    close = df['close'].values\n19\t\n20\t    tr = np.zeros(len(df))\n21\t    for i in range(len(df)):\n22\t        if i == 0:\n23\t            tr[i] = high[i] - low[i]\n24\t        else:\n25\t            tr[i] = max(\n26\t                high[i] - low[i],\n27\t                abs(high[i] - close[i-1]),\n28\t                abs(low[i] - close[i-1])\n29\t            )\n30\t\n31\t    # Wilder平滑法计算ATR\n32\t    atr = np.zeros(len(df))\n33\t    atr[period-1] = np.mean(tr[:period])\n34\t\n35\t    for i in range(period, len(df)):\n36\t        atr[i] = (atr[i-1] * (period - 1) + tr[i]) / period\n37\t\n38\t    return atr\n39\t\n40\tdef analyze_stock(client, code, target_date='2024-09-09'):\n41\t    \"\"\"\n42\t    分析单只股票是否符合ATR突破条件\n43\t    \"\"\"\n44\t    try:\n45\t        # 获取足够的历史数据（需要更多数据以覆盖2024-09-09）\n46\t        # offset参数获取最近N条，需要足够大以包含目标日期\n47\t        bars = client.bars(symbol=code, frequency=9, offset=800)\n48\t\n49\t        if bars is None or len(bars) < 80:\n50\t            return None\n51\t\n52\t        # 重置索引以避免datetime既是索引又是列的问题\n53\t        bars = bars.reset_index(drop=True)\n54\t\n55\t        # 确保datetime列存在\n56\t        if 'datetime' in bars.columns:\n57\t            bars['datetime'] = pd.to_datetime(bars['datetime'])\n58\t            bars = bars.sort_values('datetime').reset_index(drop=True)\n59\t\n60\t        # 计算ATR\n61\t        atr = calculate_atr(bars, period=14)\n62\t        bars['atr'] = atr\n63\t\n64\t        # 找到目标日期或最接近的日期\n65\t        bars['date_str'] = bars['datetime'].dt.strftime('%Y-%m-%d')\n66\t        target_idx = bars[bars['date_str'] <= target_date].index\n67\t\n68\t        if len(target_idx) == 0:\n69\t            return None\n70\t\n71\t        current_idx = target_idx[-1]\n72\t\n73\t        # 确保有足够的历史数据\n74\t        if current_idx < 60:\n75\t            return None\n76\t\n77\t        # 获取当前ATR\n78\t        current_atr = bars.loc[current_idx, 'atr']\n79\t\n80\t        if current_atr == 0 or np.isnan(current_atr):\n81\t            return None\n82\t\n83\t        # 计算近60日ATR的80分位数\n84\t        atr_60d = bars.loc[current_idx-59:current_idx, 'atr'].values\n85\t        atr_80pct = np.percentile(atr_60d[atr_60d > 0], 80)\n86\t\n87\t        # 条件1: ATR突破80分位数\n88\t        if current_atr <= atr_80pct:\n89\t            return None\n90\t\n91\t        # 条件2: 收盘价突破近20日最高价\n92\t        if current_idx < 20:\n93\t            return None\n94\t\n95\t        high_20d = bars.loc[current_idx-20:current_idx-1, 'high'].max()\n96\t        current_close = bars.loc[current_idx, 'close']\n97\t\n98\t        if current_close <= high_20d:\n99\t            return None\n100\t\n101\t        # 条件3: 成交量 > 20日均量的2倍\n102\t        vol_20d_avg = bars.loc[current_idx-20:current_idx-1, 'volume'].mean()\n103\t        current_vol = bars.loc[current_idx, 'volume']\n104\t\n105\t        if current_vol <= vol_20d_avg * 2:\n106\t            return None\n107\t\n108\t        # 条件4: 收阳且涨幅>3%\n109\t        current_open = bars.loc[current_idx, 'open']\n110\t\n111\t        if current_close <= current_open:\n112\t            return None\n113\t\n114\t        pct_change = (current_close - current_open) / current_open * 100\n115\t\n116\t        if pct_change <= 3.0:\n117\t            return None\n118\t\n119\t        # 所有条件满足，返回结果\n120\t        breakout_date = bars.loc[current_idx, 'date_str']\n121\t\n122\t        return {\n123\t            'code': code,\n124\t            'atr': round(current_atr, 2),\n125\t            'atr_80pct': round(atr_80pct, 2),\n126\t            'breakout_date': breakout_date,\n127\t            'pct_change': round(pct_change, 2)\n128\t        }\n129\t\n130\t    except Exception as e:\n131\t        print(f\"处理股票 {code} 时出错: {e}\")\n132\t        return None\n133\t\n134\tdef main():\n135\t    print(\"初始化mootdx客户端...\")\n136\t    client = Quotes.factory(market='std')\n137\t\n138\t    print(\"获取创业板股票列表...\")\n139\t    stocks = client.stocks(market=0)\n140\t    chinext = stocks[stocks['code'].str.startswith(('300', '301'))]\n141\t\n142\t    print(f\"找到 {len(chinext)} 只创业板股票\")\n143\t    print(\"开始筛选符合条件的股票...\")\n144\t\n145\t    results = []\n146\t    total = len(chinext)\n147\t\n148\t    for idx, row in chinext.iterrows():\n149\t        code = row['code']\n150\t        if (idx + 1) % 50 == 0:\n151\t            print(f\"进度: {idx + 1}/{total}\")\n152\t\n153\t        result = analyze_stock(client, code)\n154\t        if result:\n155\t            results.append(result)\n156\t            print(f\"✓ 找到符合条件的股票: {code}\")\n157\t\n158\t    print(f\"\\n筛选完成! 共找到 {len(results)} 只符合条件的股票\")\n159\t\n160\t    # 写入结果文件\n161\t    output_file = 'atr_breakout.txt'\n162\t    with open(output_file, 'w', encoding='utf-8') as f:\n163\t        if len(results) == 0:\n164\t            f.write(\"无符合条件的股票\\n\")\n165\t        else:\n166\t            f.write(\"股票代码,截至2024-09-09的ATR,ATR的60日80分位数,突破日期,当日涨幅(%)\\n\")\n167\t            for r in results:\n168\t                f.write(f\"{r['code']},{r['atr']},{r['atr_80pct']},{r['breakout_date']},{r['pct_change']}\\n\")\n169\t\n170\t    print(f\"结果已写入 {output_file}\")\n171\t\n172\t    return results\n173\t\n174\tif __name__ == '__main__':\n175\t    results = main()\n176\t\n\n<system-reminder>\nWhenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.\n</system-reminder>\n"}]},"parent_tool_use_id":null,"session_id":"6533058b-a97c-4a83-999c-6391f81e7847","uuid":"25cafccc-2bf9-4acc-b470-5cf8fa899fe1","timestamp":"2026-04-16T02:48:46.526Z","tool_use_result":{"type":"text","file":{"filePath":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_27_atr_volatility_breakout/revised/claudecode/atr_breakout_analysis.py","content":"#!/usr/bin/env python3\n\"\"\"\nATR波动率扩张突破识别\n筛选创业板中波动率扩张的股票\n\"\"\"\nfrom mootdx.quotes import Quotes\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\n\ndef calculate_atr(df, period=14):\n    \"\"\"\n    计算ATR（Average True Range）使用Wilder平滑法\n    \"\"\"\n    # 计算True Range\n    high = df['high'].values\n    low = df['low'].values\n    close = df['close'].values\n\n    tr = np.zeros(len(df))\n    for i in range(len(df)):\n        if i == 0:\n            tr[i] = high[i] - low[i]\n        else:\n            tr[i] = max(\n                high[i] - low[i],\n                abs(high[i] - close[i-1]),\n                abs(low[i] - close[i-1])\n            )\n\n    # Wilder平滑法计算ATR\n    atr = np.zeros(len(df))\n    atr[period-1] = np.mean(tr[:period])\n\n    for i in range(period, len(df)):\n        atr[i] = (atr[i-1] * (period - 1) + tr[i]) / period\n\n    return atr\n\ndef analyze_stock(client, code, target_date='2024-09-09'):\n    \"\"\"\n    分析单只股票是否符合ATR突破条件\n    \"\"\"\n    try:\n        # 获取足够的历史数据（需要更多数据以覆盖2024-09-09）\n        # offset参数获取最近N条，需要足够大以包含目标日期\n        bars = client.bars(symbol=code, frequency=9, offset=800)\n\n        if bars is None or len(bars) < 80:\n            return None\n\n        # 重置索引以避免datetime既是索引又是列的问题\n        bars = bars.reset_index(drop=True)\n\n        # 确保datetime列存在\n        if 'datetime' in bars.columns:\n            bars['datetime'] = pd.to_datetime(bars['datetime'])\n            bars = bars.sort_values('datetime').reset_index(drop=True)\n\n        # 计算ATR\n        atr = calculate_atr(bars, period=14)\n        bars['atr'] = atr\n\n        # 找到目标日期或最接近的日期\n        bars['date_str'] = bars['datetime'].dt.strftime('%Y-%m-%d')\n        target_idx = bars[bars['date_str'] <= target_date].index\n\n        if len(target_idx) == 0:\n            return None\n\n        current_idx = target_idx[-1]\n\n        # 确保有足够的历史数据\n        if current_idx < 60:\n            return None\n\n        # 获取当前ATR\n        current_atr = bars.loc[current_idx, 'atr']\n\n        if current_atr == 0 or np.isnan(current_atr):\n            return None\n\n        # 计算近60日ATR的80分位数\n        atr_60d = bars.loc[current_idx-59:current_idx, 'atr'].values\n        atr_80pct = np.percentile(atr_60d[atr_60d > 0], 80)\n\n        # 条件1: ATR突破80分位数\n        if current_atr <= atr_80pct:\n            return None\n\n        # 条件2: 收盘价突破近20日最高价\n        if current_idx < 20:\n            return None\n\n        high_20d = bars.loc[current_idx-20:current_idx-1, 'high'].max()\n        current_close = bars.loc[current_idx, 'close']\n\n        if current_close <= high_20d:\n            return None\n\n        # 条件3: 成交量 > 20日均量的2倍\n        vol_20d_avg = bars.loc[current_idx-20:current_idx-1, 'volume'].mean()\n        current_vol = bars.loc[current_idx, 'volume']\n\n        if current_vol <= vol_20d_avg * 2:\n            return None\n\n        # 条件4: 收阳且涨幅>3%\n        current_open = bars.loc[current_idx, 'open']\n\n        if current_close <= current_open:\n            return None\n\n        pct_change = (current_close - current_open) / current_open * 100\n\n        if pct_change <= 3.0:\n            return None\n\n        # 所有条件满足，返回结果\n        breakout_date = bars.loc[current_idx, 'date_str']\n\n        return {\n            'code': code,\n            'atr': round(current_atr, 2),\n            'atr_80pct': round(atr_80pct, 2),\n            'breakout_date': breakout_date,\n            'pct_change': round(pct_change, 2)\n        }\n\n    except Exception as e:\n        print(f\"处理股票 {code} 时出错: {e}\")\n        return None\n\ndef main():\n    print(\"初始化mootdx客户端...\")\n    client = Quotes.factory(market='std')\n\n    print(\"获取创业板股票列表...\")\n    stocks = client.stocks(market=0)\n    chinext = stocks[stocks['code'].str.startswith(('300', '301'))]\n\n    print(f\"找到 {len(chinext)} 只创业板股票\")\n    print(\"开始筛选符合条件的股票...\")\n\n    results = []\n    total = len(chinext)\n\n    for idx, row in chinext.iterrows():\n        code = row['code']\n        if (idx + 1) % 50 == 0:\n            print(f\"进度: {idx + 1}/{total}\")\n\n        result = analyze_stock(client, code)\n        if result:\n            results.append(result)\n            print(f\"✓ 找到符合条件的股票: {code}\")\n\n    print(f\"\\n筛选完成! 共找到 {len(results)} 只符合条件的股票\")\n\n    # 写入结果文件\n    output_file = 'atr_breakout.txt'\n    with open(output_file, 'w', encoding='utf-8') as f:\n        if len(results) == 0:\n            f.write(\"无符合条件的股票\\n\")\n        else:\n            f.write(\"股票代码,截至2024-09-09的ATR,ATR的60日80分位数,突破日期,当日涨幅(%)\\n\")\n            for r in results:\n                f.write(f\"{r['code']},{r['atr']},{r['atr_80pct']},{r['breakout_date']},{r['pct_change']}\\n\")\n\n    print(f\"结果已写入 {output_file}\")\n\n    return results\n\nif __name__ == '__main__':\n    results = main()\n","numLines":176,"startLine":1,"totalLines":176}}}
